/*
 * 低功耗模式分层配置框架
 * 
 * 设计原则（《UNIX编程艺术》ch.6 模块原则）：
 * 1. 每层只负责一个维度的功耗优化
 * 2. 层与层之间通过标准化接口交互
 * 3. 上层不需要知道下层的寄存器细节
 *
 * 适用平台：STM32L476RG @ 80MHz (main) + 32.768kHz (LSI)
 * 电池：CR2032 220mAh，目标寿命 3 年
 */

#include <stm32l4xx_hal.h>
#include <stdint.h>
#include <stdbool.h>

/* ========== 第一层：硅片级功耗模式配置 ========== */

/* 功耗模式枚举 —— 从低到高 */
typedef enum {
    LP_RUN_MODE = 0,       /* 运行模式，约 40mA */
    LP_SLEEP_MODE,          /* Sleep，约 35mA，退出 0.25us */
    LP_STOP0_MODE,          /* Stop 0，约 2.2uA，退出 5us */
    LP_STOP1_MODE,          /* Stop 1，约 1.6uA，退出 5us */
    LP_STOP2_MODE,          /* Stop 2，约 0.8uA，退出 5us */
    LP_STANDBY_MODE         /* Standby，约 40nA，退出 3ms */
} lp_mode_t;

/* 进入指定低功耗模式（HAL 层抽象）*/
static void enter_lp_mode(lp_mode_t mode)
{
    switch (mode) {
    case LP_SLEEP_MODE:
        /* 仅关闭 Cortex-M Core 时钟，外设仍在运行 */
        __WFI();  /* Wait For Interrupt */
        break;
    case LP_STOP0_MODE:
        /* 关闭 PLL 和 HSI，进入 Stop 0 */
        /* 1. 选择 Voltage Scaling Range 1 (最低功耗) */
        HAL_PWREx_ControlVoltageScaling(PWR_REGULATOR_VOLTAGE_SCALE1);
        /* 2. 进入 Stop 0 模式 */
        HAL_PWR_EnterSTOPMode(PWR_LOWPOWERREGULATOR_ON, PWR_STOPENTRY_WFI);
        /* 3. Wake-up: 系统自动从 STOP 恢复，HSI 作为系统时钟 */
        /* 4. 重新配置 PLL 回到 80MHz */
        SystemClock_Config();
        break;
    case LP_STANDBY_MODE:
        /* 切断 1.8V 域，仅保留 Backup 域 */
        HAL_PWR_EnableWakeUpPin(PWR_WAKEUP_PIN1);
        HAL_PWR_EnableWakeUpPin(PWR_WAKEUP_PIN2);
        /* 启用 VBATT 监测（可选，增加 ~1uA 功耗）*/
        // HAL_PWREx_EnableVddBXDomain();
        HAL_PWR_EnterSTANDBYMode();
        /* 永远不会执行到这里 —— Standby 唤醒 = 复位 */
        break;
    default:
        break;
    }
}

/* ========== 第二层：时钟树门控 ========== */

/* 关闭所有未使用的外设时钟 */
static void clock_gate_unused_peripherals(void)
{
    /* RCC_APB1ENR1 位定义 */
    /* 关闭 I2C3/I2C4（未使用）*/
    RCC->APB1ENR1 &= ~(RCC_APB1ENR1_I2C3EN | RCC_APB1ENR1_I2C4EN);
    /* 关闭 TIM2/TIM3/TIM5（未使用）*/
    RCC->APB1ENR1 &= ~(RCC_APB1ENR1_TIM2EN | RCC_APB1ENR1_TIM3EN | RCC_APB1ENR1_TIM5EN);
    /* 关闭 UART4/UART5（未使用）*/
    RCC->APB1ENR1 &= ~(RCC_APB1ENR1_UART4EN | RCC_APB1ENR1_UART5EN);

    /* RCC_APB2ENR 位定义 */
    /* 关闭 ADC2/ADC3（未使用）*/
    RCC->APB2ENR &= ~(RCC_APB2ENR_ADC2EN | RCC_APB2ENR_ADC3EN);

    /* RCC_AHB2ENR —— 关闭未使用的 GPIO 端口 */
    /* 假设只用 GPIOA, GPIOB, GPIOC, GPIOD, GPIOH */
    RCC->AHB2ENR &= ~(RCC_AHB2ENR_GPIOEEN | RCC_AHB2ENR_GPIOFEN | 
                      RCC_AHB2ENR_GPIOGEN | RCC_AHB2ENR_GPIOHEN);
}

/* ========== 第三层：唤醒源管理 ========== */

typedef enum {
    WK_RTC_ALARM = 0,    /* RTC Alarm A —— 周期性唤醒 */
    WK_EXTI_PB0,          /* 外部按键 PB0 —— 事件驱动 */
    WK_EXTI_PB13,         /* 用户按钮 Blue Button */
    WK_IWDG_TIMEOUT,      /* 看门狗超时 —— 安全唤醒 */
    WK_USART1_RX          /* USART1 接收字符 —— 通信唤醒 */
} wake_source_t;

/* 配置指定唤醒源 */
static void configure_wake_source(wake_source_t source)
{
    EXTI_InitTypeDef EXTI_InitStruct = {0};

    switch (source) {
    case WK_EXTI_PB0:
        /* 使能 GPIOA 时钟（用于 EXTI 配置）*/
        __HAL_RCC_GPIOA_CLK_ENABLE();
        /* PB0 映射到 EXTI Line 16 */
        HAL_SYSCFG_EXTPasswordConfig(SYSCFG_CMPCR_CMP_PD);
        GPIO_InitTypeDef GPIO_InitStruct = {0};
        GPIO_InitStruct.Pin = GPIO_PIN_0;
        GPIO_InitStruct.Mode = GPIO_MODE_IT_FALLING;
        GPIO_InitStruct.Pull = GPIO_PULLUP;
        HAL_GPIO_Init(GPIOB, &GPIO_InitStruct);
        HAL_NVIC_SetPriority(EXTI0_IRQn, 2, 0);
        HAL_NVIC_EnableIRQ(EXTI0_IRQn);
        break;

    case WK_RTC_ALARM:
        /* RTC Alarm A 在 Stop 模式下仍有效（由 LSI 驱动）*/
        /* 设置 Alarm A 每 60 秒触发一次 */
        RTC_AlarmTypeDef sAlarm = {0};
        sAlarm.Alarm = RTC_ALARM_A;
        sAlarm.AlarmTime.SubSeconds = 0;
        sAlarm.AlarmMask = RTC_ALARMMASK_NONE;
        sAlarm.AlarmSubSecondMask = RTC_ALARMSUBSECONDMASK_ALL;
        sAlarm.AlarmDateWeekDaySel = RTC_ALARMDATEWEEKDAYSEL_DATE;
        sAlarm.AlarmDateWeekDay = 1;  /* 任意日期 */
        sAlarm.AlarmTime.Hours = 0;
        sAlarm.AlarmTime.Minutes = 0;
        sAlarm.AlarmTime.Seconds = 60;  /* 60 秒后触发 */
        HAL_RTC_SetAlarm_IT(&hrtc, &sAlarm, RTC_FORMAT_BIN);
        break;

    case WK_IWDG_TIMEOUT:
        /* 独立看门狗在 Stop 模式下不可用（需要 LSI，但 IWDG 在 Stop 被禁用）*/
        /* 只能在 Sleep 模式下使用 IWDG 唤醒 */
        /* 改用 RTC 作为周期性唤醒源，IWDG 仅用于安全超时 */
        break;
    }
}

/* ========== 第四层：能量账本计算 ========== */

/* 简单的能量预算结构 */
typedef struct {
    uint32_t active_current_uA;    /* 活跃电流 (uA) */
    uint32_t active_duration_ms;   /* 每次活跃持续时间 (ms) */
    uint32_t sleep_current_uA;     /* 睡眠电流 (uA) */
    uint32_t sleep_duration_ms;    /* 每次睡眠持续时间 (ms) */
    uint32_t transitions_per_day;  /* 每日模式切换次数 */
    uint32_t transition_current_uA;/* 切换平均电流 (uA) */
    uint32_t transition_duration_us; /* 切换持续时间 (us) */
} energy_budget_t;

/* 计算每日能耗 (mAh) */
static float calc_daily_energy_mah(const energy_budget_t *budget)
{
    /* 活跃能耗 */
    float e_active = (float)budget->active_current_uA * budget->active_duration_ms / 1000.0f;
    /* 睡眠能耗 */
    float e_sleep = (float)budget->sleep_current_uA * budget->sleep_duration_ms / 1000.0f;
    /* 切换能耗 */
    float e_trans = (float)budget->transition_current_uA * budget->transition_duration_us / 1000000.0f * budget->transitions_per_day;

    /* 单次循环能耗 (uAh)，乘以每日循环次数 */
    float cycles_per_day = 86400000.0f / (budget->active_duration_ms + budget->sleep_duration_ms);
    float daily_uAh = (e_active + e_sleep + e_trans) * cycles_per_day;

    return daily_uAh / 1000.0f;  /* 转换为 mAh */
}

/* 示例：STM32L476 在 CR2032 电池上的 3 年寿命预算 */
int main_check_battery_life(void)
{
    energy_budget_t budget = {
        .active_current_uA = 4000,       /* 80MHz + USART 发送 */
        .active_duration_ms = 50,        /* 每次 50ms */
        .sleep_current_uA = 2,           /* Stop 0 模式 */
        .sleep_duration_ms = 59950,      /* 每次 59.95s */
        .transitions_per_day = 1440,     /* 每天 1440 次（每 60s 一次）*/
        .transition_current_uA = 1000,   /* 切换平均 1mA */
        .transition_duration_us = 5000   /* 5us 切换时间 */
    };

    float daily_mah = calc_daily_energy_mah(&budget);
    float yearly_mah = daily_mah * 365;
    float three_year_mah = yearly_mah * 3;

    /* CR2032 典型容量约 220mAh */
    /* 如果 three_year_mah > 220，需要优化 */
    return (three_year_mah <= 220) ? 0 : 1;
}

/*
 * RTC Alarm 周期性唤醒 —— 正确序列
 * 
 * STM32L476: LSE = 32.768kHz, Stop 0 模式
 * 唤醒间隔: 60 秒
 * 目标平均电流: < 2.5μA
 * 
 * 中断优先级设置:
 *   NVIC_SetPriority(EXTI21_TS_IRQn, 5)   /* RTC Alarm */
 *   NVIC_SetPriority(WWDG_IRQn, 4)        /* 窗口看门狗（稍高）*/
 *   NVIC_SetPriority(PendSV_IRQn, 15)     /* FreeRTOS PendSV（最低）*/
 */

#include <stm32l4xx_hal.h>
#include <stdint.h>

/* 唤醒间隔（秒）*/
#define WAKE_INTERVAL_SEC   60

/* LSE 频率 */
#define LSE_FREQ_HZ         32768

/* RTC 唤醒定时器预分频配置 */
/* WUCKSEL[1:0] = 0b10 → LSE / 128 = 256Hz */
/* WUT = (256 - 1) * 60 = 15359 → 60 秒唤醒 */
#define RTC_WUCKSEL_DIV     128
#define RTC_WAKE_COUNTER    ((LSE_FREQ_HZ / RTC_WUCKSEL_DIV) * WAKE_INTERVAL_SEC - 1)

/* 保存系统时钟配置的缓冲区 */
static FLASH_OperationTypeDef saved_clock_config;

/**
 * @brief  保存当前系统时钟配置
 *         从 Stop 模式唤醒后需要用此配置恢复 PLL
 */
static void save_clock_configuration(void)
{
    /* 读取时钟树状态寄存器 */
    saved_clock_config.SWS = RCC->CFGR & RCC_CFGR_SWS_Msk;
    saved_clock_config.SW = RCC->CFGR & RCC_CFGR_SW_Msk;
    saved_clock_config.HSIDIV = (RCC->CFGR >> 3) & 0x7;
    saved_clock_config.PRES = RCC->CFGR & 0xF80FC000;
    /* 保存 PLL 配置 */
    saved_clock_config.PLL_R = (RCC->PLLCFGR >> 27) & 0x7;
    saved_clock_config.PLL_N = (RCC->PLLCFGR >> 8) & 0x1FF;
    saved_clock_config.PLL_M = RCC->PLLCFGR & 0x3F;
}

/**
 * @brief  恢复系统时钟到之前的配置
 *         必须在所有外设初始化之前调用
 */
static void restore_clock_configuration(void)
{
    /* 重新配置 PLL */
    RCC->PLLCFGR = (saved_clock_config.PLL_M) |
                   (saved_clock_config.PLL_N << 8) |
                   (saved_clock_config.PLL_R << 27);
    /* 启动 PLL */
    RCC->CR |= RCC_CR_PLLON;
    while (!(RCC->CR & RCC_CR_PLLRDY));
    /* 切换系统时钟 */
    RCC->CFGR = (RCC->CFGR & ~RCC_CFGR_SW_Msk) | saved_clock_config.SW;
    while ((RCC->CFGR & RCC_CFGR_SWS_Msk) != saved_clock_config.SWS);
}

/**
 * @brief  进入 Stop 0 模式，由 RTC Alarm 唤醒
 * @retval HAL_OK 如果唤醒成功
 */
HAL_StatusTypeDef lowpower_enter_stop_with_rtc_alarm(RTC_HandleTypeDef *hrtc)
{
    /* 第 1 步：保存时钟配置（唤醒后需要恢复）*/
    save_clock_configuration();

    /* 第 2 步：使能 RTC Alarm A 中断 */
    HAL_NVIC_SetPriority(RTC_Alarm_IRQn, 5, 0);
    HAL_NVIC_EnableIRQ(RTC_Alarm_IRQn);

    /* 第 3 步：配置 Alarm A 唤醒间隔 */
    RTC_AlarmTypeDef sAlarm = {0};
    sAlarm.Alarm = RTC_ALARM_A;
    sAlarm.AlarmSubSecondMask = RTC_ALARMSUBSECONDMASK_ALL;
    sAlarm.AlarmDateWeekDaySel = RTC_ALARMDATEWEEKDAYSEL_DATE;
    sAlarm.AlarmDateWeekDay = 1;
    sAlarm.AlarmTime.Hours   = 0;
    sAlarm.AlarmTime.Minutes = 0;
    sAlarm.AlarmTime.Seconds = WAKE_INTERVAL_SEC;

    if (HAL_RTC_SetAlarm_IT(hrtc, &sAlarm, RTC_FORMAT_BIN) != HAL_OK) {
        return HAL_ERROR;
    }

    /* 第 4 步：关闭未使用的外设时钟（减少漏电流）*/
    clock_gate_unused_peripherals();

    /* 第 5 步：关闭 VREFINT 和温度传感器（每路 ~1μA）*/
    HAL_PWREx_DisableVREFINT();
    HAL_PWREx_DisableInternalWakeUpLine();

    /* 第 6 步：进入 Stop 0 模式 */
    /* 关键：必须先调用 HAL_PWR_EnterSTOPMode，再调用 __WFI */
    /* HAL 库会在内部设置 PWR_CR1 的 LPMS 字段为 STOP_0 */
    HAL_PWR_EnterSTOPMode(PWR_LOWPOWERREGULATOR_ON, PWR_STOPENTRY_WFI);

    /* 以下代码在唤醒后执行 */
    /* HAL 库已自动将电压调节器恢复到正常运行模式 */

    /* 第 7 步：恢复 VREFINT（如果需要 ADC）*/
    HAL_PWREx_EnableVREFINT();

    /* 第 8 步：恢复系统时钟 */
    restore_clock_configuration();

    /* 第 9 步：清除 RTC Alarm 标志（必须在恢复时钟前完成）*/
    __HAL_RTC_ALARM_CLEAR_FLAG(hrtc, RTC_FLAG_ALRAF);

    /* 第 10 步：重新使能外设时钟 */
    __HAL_RCC_GPIOA_CLK_ENABLE();
    __HAL_RCC_USART1_CLK_ENABLE();

    return HAL_OK;
}

/**
 * @brief  RTC Alarm 中断服务函数
 *         在中断中只做标志清除，不做耗时操作
 */
void RTC_Alarm_IRQHandler(void)
{
    HAL_RTC_AlarmIRQHandler(&hrtc);
}

void HAL_RTC_AlarmAEventCallback(RTC_HandleTypeDef *hrtc)
{
    /* 清除标志 —— 这一步在 HAL 库中已完成 */
    /* 如果需要，可以在这里设置一个标志位，由主循环处理 */
    __HAL_RTC_ALARM_CLEAR_FLAG(hrtc, RTC_FLAG_ALRAF);
}

/*
 * 低功耗陷阱检测工具 —— 在代码中嵌入自检逻辑
 * 
 * 这些自检不是多余的——它们在示波器帮你找到 bug 之前，
 * 先用逻辑告诉你哪里出了问题。
 */

#include <stm32l4xx_hal.h>
#include <stdint.h>

/**
 * @brief  自检：检查 SWD 引脚是否在进入低功耗前被正确配置
 * @retval 0 = 通过, 1 = 发现 SWD 引脚仍在 GPIO 模式（漏电风险）
 */
static int check_swd_pins_configured_for_lp(void)
{
    /* PA13 = SWDIO, PA14 = SWCLK */
    uint32_t moder_a = GPIOA->MODER;

    /* MODER[1:0] of PA13 should be 0b00 (Analog) */
    if ((moder_a & (0x3 << (13 * 2))) != 0) {
        /* PA13 不是模拟输入 —— 漏电！*/
        return 1;
    }

    /* MODER[3:2] of PA14 should be 0b00 (Analog) */
    if ((moder_a & (0x3 << (14 * 2))) != 0) {
        /* PA14 不是模拟输入 —— 漏电！*/
        return 1;
    }

    return 0;
}

/**
 * @brief  自检：检查 LSE 晶振是否正常起振
 *         在 -40°C 环境下特别重要
 * @retval 0 = LSE 正常, 1 = LSE 未就绪（回退到 LSI）
 */
static int check_lse_ready_with_timeout(uint32_t timeout_ms)
{
    uint32_t start = HAL_GetTick();

    while ((HAL_GetTick() - start) < timeout_ms) {
        if (RCC->BDCR & RCC_BDCR_LSERDY) {
            return 0;  /* LSE 就绪 */
        }
        HAL_Delay(1);
    }

    /* 超时 —— 回退到 LSI */
    RCC->CSR |= RCC_CSR_LSION;  /* 使能 LSI */
    while (!(RCC->CSR & RCC_CSR_LSIRDY));  /* 等待 LSI 就绪 */
    RCC->BDCR &= ~RCC_BDCR_RTCSEL_Msk;
    RCC->BDCR |= RCC_BDCR_RTCSEL_0;  /* 选择 LSI 作为 RTC 时钟源 */
    return 1;  /* 已回退 */
}

/**
 * @brief  自检：检查 Backup SRAM 的魔术数
 *         用于验证 Standby 唤醒后数据是否完整
 * @retval 0 = 数据完整, 1 = 数据丢失（Standby 唤醒）
 */
#define BKPDAT_MAGIC  0xDEADBEEF

static int check_backup_sram_integrity(void)
{
    uint32_t magic = *(volatile uint32_t *)0x4002  4000;  /* BKPDAT 起始地址 */
    return (magic == BKPDAT_MAGIC) ? 0 : 1;
}

/**
 * @brief  进入 Stop 前的最终安全检查
 *         如果任何检查失败，记录错误并继续（不进入 Stop）
 * @retval 0 = 可以安全进入 Stop, 1 = 存在风险，跳过 Stop
 */
int pre_stop_self_check(void)
{
    int risk = 0;

    /* 检查 1: SWD 引脚配置 */
    if (check_swd_pins_configured_for_lp() != 0) {
        /* 设置 GPIO 翻转标记以便调试 */
        HAL_GPIO_TogglePin(GPIOB, GPIO_PIN_0);
        risk = 1;
    }

    /* 检查 2: LSE 就绪 */
    if (check_lse_ready_with_timeout(100) != 0) {
        /* 使用 LSI 而非 LSE，精度下降 */
        risk = 1;
    }

    /* 检查 3: 电压调节器状态 */
    if ((PWR->CR1 & PWR_CR1_VOS) == 0) {
        /* 电压等级不是 Scale 1 —— 电流偏高 */
        risk = 1;
    }

    return risk;
}

