/* --- power_mgr.h --- */
#ifndef POWER_MGR_H
#define POWER_MGR_H

typedef enum {
    POWER_MODE_RUN = 0,
    POWER_MODE_SLEEP,
    POWER_MODE_STOP0,
    POWER_MODE_STOP1,
    POWER_MODE_STANDBY
} power_mode_t;

/* 进入指定功耗模式，返回实际进入的模式（可能因条件不满足而降级）*/
power_mode_t power_enter_mode(power_mode_t requested);

/* 获取当前功耗模式 */
power_mode_t power_get_current_mode(void);

/* 获取进入低功耗前的配置快照 */
void power_save_context(void);

/* 恢复进入低功耗前的配置 */
void power_restore_context(void);

#endif

/* --- power_mgr.c --- */
#include "power_mgr.h"
#include <stm32l4xx_hal.h>

static power_mode_t current_mode = POWER_MODE_RUN;

power_mode_t power_enter_mode(power_mode_t requested)
{
    power_save_context();

    switch (requested) {
    case POWER_MODE_SLEEP:
        current_mode = POWER_MODE_SLEEP;
        __WFI();
        break;

    case POWER_MODE_STOP0:
        /* 关闭 VREFINT 和内部唤醒线 */
        HAL_PWREx_DisableVREFINT();
        HAL_PWREx_DisableInternalWakeUpLine();
        /* 关闭未使用的 GPIO 时钟 */
        RCC->AHB2ENR &= ~(RCC_AHB2ENR_GPIOEEN | RCC_AHB2ENR_GPIOFEN |
                          RCC_AHB2ENR_GPIOGEN);
        current_mode = POWER_MODE_STOP0;
        HAL_PWREx_ControlVoltageScaling(PWR_REGULATOR_VOLTAGE_SCALE1);
        HAL_PWR_EnterSTOPMode(PWR_LOWPOWERREGULATOR_ON, PWR_STOPENTRY_WFI);
        /* 唤醒后恢复 */
        current_mode = POWER_MODE_RUN;
        break;

    case POWER_MODE_STANDBY:
        HAL_PWR_EnableWakeUpPin(PWR_WAKEUP_PIN1);
        current_mode = POWER_MODE_STANDBY;
        HAL_PWR_EnterSTANDBYMode();
        /* 不会执行到这里 */
        break;

    default:
        break;
    }

    power_restore_context();
    return current_mode;
}

power_mode_t power_get_current_mode(void)
{
    return current_mode;
}

/* --- wake_mgr.h --- */
#ifndef WAKE_MGR_H
#define WAKE_MGR_H

typedef enum {
    WAKE_NONE = 0,
    WAKE_RTC_ALARM,
    WAKE_EXTI_PB0,
    WAKE_BUTTON_PRESS,
    WAKE_USART_RX
} wake_event_t;

/* 检查并清除唤醒事件，返回触发原因 */
wake_event_t wake_get_event(void);

/* 配置指定唤醒源 */
void wake_configure_source(wake_event_t source);

/* 清除所有唤醒标志 */
void wake_clear_all(void);

#endif

/* --- wake_mgr.c --- */
#include "wake_mgr.h"
#include <stm32l4xx_hal.h>

wake_event_t wake_get_event(void)
{
    /* 检查 RTC Alarm */
    if (__HAL_RTC_ALARM_GET_FLAG(&hrtc, RTC_FLAG_ALRAF)) {
        __HAL_RTC_ALARM_CLEAR_FLAG(&hrtc, RTC_FLAG_ALRAF);
        return WAKE_RTC_ALARM;
    }

    /* 检查 EXTI */
    if (__HAL_GPIO_EXTI_GET_IT(GPIO_PIN_0)) {
        __HAL_GPIO_EXTI_CLEAR_IT(GPIO_PIN_0);
        return WAKE_EXTI_PB0;
    }

    return WAKE_NONE;
}

/* --- main.c —— 重构后的主循环 --- */
int main(void)
{
    HAL_Init();
    SystemClock_Config();

    /* 初始化各层模块 */
    power_init();
    wake_configure_source(WAKE_RTC_ALARM);
    wake_configure_source(WAKE_EXTI_PB0);

    /* 主循环 —— 只负责调度 */
    while (1) {
        /* 1. 处理唤醒事件 */
        wake_event_t event = wake_get_event();

        /* 2. 执行应用任务 */
        switch (event) {
        case WAKE_RTC_ALARM:
            /* 周期性任务：采集传感器数据 */
            adc_read_and_send();
            break;

        case WAKE_EXTI_PB0:
            /* 事件驱动任务：按键触发 */
            button_handler();
            break;

        case WAKE_NONE:
            /* 首次启动，执行完整初始化 */
            system_init_complete();
            break;

        default:
            break;
        }

        /* 3. 进入低功耗（如果应用允许）*/
        if (app_can_sleep()) {
            power_enter_mode(POWER_MODE_STOP0);
        }
    }
}
